export declare const staticLinksTemplate = "\"use client\";\nimport { useContext } from \"react\";\nimport styled, { css } from \"styled-components\";\nimport { mq, Theme } from \"@/app/theme\";\nimport { ChatContext } from \"@/components/Chat\";\nimport linksData from \"@/links.json\";\n\ninterface LinkProps {\n  title: string;\n  url: string;\n}\n\nconst links = linksData as LinkProps[];\n\nconst StyledStaticLinks = styled.div<{ theme: Theme; $isChatOpen?: boolean }>`\n  position: fixed;\n  border-bottom: solid 1px ${({ theme }) => theme.colors.grayLight};\n  top: 70px;\n  padding: 20px;\n  display: flex;\n  justify-content: space-between;\n  width: 100%;\n  z-index: 999;\n  transition: all 0.3s ease;\n  margin: auto;\n  height: 73px;\n  background: ${({ theme }) => theme.colors.light};\n  overflow-x: auto;\n  left: 50%;\n  transform: translateX(-50%);\n\n  ${mq(\"lg\")} {\n    top: 0;\n    max-width: calc(100vw - 640px);\n    width: 100%;\n    margin: auto;\n\n    ${({ $isChatOpen }) =>\n      $isChatOpen &&\n      css`\n        padding: 20px 120px 20px 20px;\n      `}\n  }\n`;\n\nconst StyledStaticLinksContent = styled.div`\n  margin: auto 0;\n  display: flex;\n  gap: 16px;\n  flex-wrap: nowrap;\n`;\n\nconst StyledLink = styled.a<{ theme: Theme }>`\n  text-decoration: none;\n  font-size: ${({ theme }) => theme.fontSizes.small.lg};\n  line-height: 1;\n  color: ${({ theme }) =>\n    theme.isDark ? theme.colors.primary : theme.colors.primary};\n  padding: 0;\n  display: flex;\n  transition: all 0.3s ease;\n  font-weight: 600;\n  white-space: nowrap;\n  min-width: fit-content;\n\n  &:last-of-type {\n    padding-right: 20px;\n  }\n\n  @media (hover: hover) {\n    &:hover {\n      color: ${({ theme }) =>\n        theme.isDark ? theme.colors.primaryLight : theme.colors.primaryDark};\n    }\n  }\n`;\n\nfunction StaticLinks() {\n  const { isOpen } = useContext(ChatContext);\n\n  if (links.length === 0) {\n    return null;\n  }\n\n  return (\n    <>\n      <StyledStaticLinks $isChatOpen={isOpen}>\n        <StyledStaticLinksContent>\n          {links.map((link, index) => (\n            <StyledLink\n              key={index}\n              href={link.url}\n              target=\"_blank\"\n              rel=\"noopener noreferrer\"\n            >\n              {link.title}\n            </StyledLink>\n          ))}\n        </StyledStaticLinksContent>\n      </StyledStaticLinks>\n    </>\n  );\n}\n\nexport { StaticLinks };\n";
